// 黑车2
(maindata, torrent) => {
  const categoryList = ["不删"];
  const ruleData = [
    { down: 60, up: 75 },
    { down: 50, up: 60 },
    { down: 40, up: 45 },
    { down: 35, up: 35 },
    { down: 30, up: 28 },
    { down: 25, up: 18 },
    { down: 20, up: 14 },
    { down: 15, up: 8 },
    { down: 10, up: 5 },
    { down: 5, up: 1 }
  ];
  const { state, upspeed, dlspeed, category } = torrent.originProp;
  if (categoryList.indexOf(category) !== -1) {
    return false;
  }
  if (
    (moment().hour() >= 0 && moment().hour() <= 8)
  ) {
    return false;
  }
  if (
      maindata.uploadSpeed >= util.calSize(90, 'MiB') ||
      maindata.downloadSpeed <= util.calSize(65, 'MiB')
  ) {
    return false;
  }
  for (const rule of ruleData) {
    if (
      state == "downloading" &&
      dlspeed >= util.calSize(rule.down, "MiB") &&
      upspeed <= util.calSize(rule.up, "MiB")
    ) {
      return true;
    }
  }
  return false;
};
